// Простой Bootstrap JavaScript для основных функций
(function() {
    'use strict';
    
    // Collapse функциональность
    function initCollapse() {
        document.addEventListener('click', function(e) {
            if (e.target.matches('[data-bs-toggle="collapse"]')) {
                e.preventDefault();
                const target = e.target.getAttribute('data-bs-target');
                const targetElement = document.querySelector(target);
                
                if (targetElement) {
                    const isCollapsed = targetElement.classList.contains('show');
                    
                    if (isCollapsed) {
                        targetElement.classList.remove('show');
                        e.target.setAttribute('aria-expanded', 'false');
                    } else {
                        targetElement.classList.add('show');
                        e.target.setAttribute('aria-expanded', 'true');
                    }
                }
            }
        });
    }
    
    // Modal функциональность
    function initModal() {
        // Показать модальное окно
        window.showModal = function(modalId) {
            const modal = document.getElementById(modalId);
            if (modal) {
                modal.style.display = 'block';
                modal.classList.add('show');
                document.body.classList.add('modal-open');
            }
        };
        
        // Скрыть модальное окно
        window.hideModal = function(modalId) {
            const modal = document.getElementById(modalId);
            if (modal) {
                modal.style.display = 'none';
                modal.classList.remove('show');
                document.body.classList.remove('modal-open');
            }
        };
        
        // Закрытие по клику на backdrop или кнопку закрытия
        document.addEventListener('click', function(e) {
            if (e.target.matches('[data-bs-dismiss="modal"]') || 
                e.target.classList.contains('modal') && e.target === e.currentTarget) {
                const modal = e.target.closest('.modal');
                if (modal) {
                    hideModal(modal.id);
                }
            }
        });
    }
    
    // Bootstrap класс
    window.bootstrap = {
        Modal: {
            getInstance: function(element) {
                return {
                    show: function() { showModal(element.id); },
                    hide: function() { hideModal(element.id); }
                };
            }
        }
    };
    
    // Инициализация при загрузке DOM
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', function() {
            initCollapse();
            initModal();
        });
    } else {
        initCollapse();
        initModal();
    }
})();
